window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2018>1","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"Members of a society are expected to adhere to societal values for the following reasons except","images":[],"options":{"A":"Enhancement of development","B":"Improvement of self dignity","C":"Reduction of social vices","D":"Relegation of morality"},"answer":"D","explanation":"Adhering to societal values is not expected to lead to the relegation of morality. On the contrary, societal values are often designed to uphold and promote morality. Therefore, the option 'Relegation of morality' is not a correct reason for members of a society to adhere to societal values.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>2","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"An attribute of honesty is","images":[],"options":{"A":"Tolerance","B":"Justice","C":"Compromise","D":"Liberty"},"answer":"B","explanation":"Honesty is closely related to justice. When a person is honest, they are fair and just in their actions and dealings with others. They do not cheat, lie, or steal, which are all actions that are considered unjust. Therefore, 'Justice' is an attribute of honesty.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>3","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"Discipline is describe as the","images":[],"options":{"A":"ability to show hospitality","B":"State or quality of being brave","C":"Tendency to fight","D":"ability to behave in a controlled manner"},"answer":"D","explanation":"Discipline is generally defined as the practice of training people to obey rules or a code of behavior, using punishment to correct disobedience. In other words, it is the ability to behave in a controlled manner. Therefore, the correct answer is option 4.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>4","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : DUTIES AND OBLIGATIONS OF CITIZENS","question":"The saying, \"ask for what you can do for your country and not what your country can do for you\" denotes that","images":[],"options":{"A":"The country owes you no obligation as a citizen","B":"Citizens have both constitutional rights and obligations","C":"Fundamental rights are to be safeguarded by citizens","D":"Service and reward do not go together"},"answer":"B","explanation":"The saying, \"ask for what you can do for your country and not what your country can do for you\" implies that as citizens, we have both rights and obligations. It means that citizens should not only expect to receive benefits from their country but should also be ready to contribute to the betterment of the country. Therefore, the correct answer is option 2.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>5","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS","question":"In the contemporary society, youths can display nationalistic role by showing the following attitudes except","images":[],"options":{"A":"Discouraging corrupt practices","B":"Exploiting the environment for the betterment of the people","C":"Contributing to the development of the society","D":"Showing indifference to national issues"},"answer":"B","explanation":"Exploiting the environment for the betterment of the people is not a nationalistic role. Nationalistic roles involve actions that promote the unity, development, and well-being of a nation. Exploiting the environment often leads to environmental degradation, which is harmful to the nation's people and its future. Therefore, this option is not a way for youths to display nationalistic roles.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>6","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"The defence of the territorial integrity of a country by her citizens is part of","images":[],"options":{"A":"Political participation","B":"Self determination","C":"Political culture","D":"Duties and Obligations"},"answer":"D","explanation":"The defence of the territorial integrity of a country by her citizens is part of their duties and obligations. Every citizen has a responsibility to protect their country's territorial integrity, whether through military service, reporting threats, or supporting the country's defense efforts. This is a duty and obligation of citizenship, not necessarily a part of political participation, self-determination, or political culture.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>7","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : ROLES OF INDIVIDUALS, GROUPS AND GOVERNMENT IN UDHR","question":"An agency established by Federal Government of Nigeria to protect rights of citizens is","images":[],"options":{"A":"Centre for Human Rights and Development","B":"Human Right Watch","C":"Legal Aid Council","D":"Human Rights Monitor"},"answer":"C","explanation":"The Legal Aid Council is a parastatal of the Federal Ministry of Justice established by the Legal Aid Act 1976 to provide free legal services to Nigerian citizens who cannot afford the cost of private legal services.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>8","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)","question":"The Universal Declaration of Human Rights (UDHR) is related to","images":[],"options":{"A":"Economic Community of West African States (ECOWAS)","B":"United Nations Organisations (UNO)","C":"African Union (AU)","D":"European Union (EU)"},"answer":"B","explanation":"The Universal Declaration of Human Rights (UDHR) is a milestone document in the history of human rights that was proclaimed by the United Nations General Assembly in Paris on 10 December 1948.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>9","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR","question":"The best means through which individual rights can be safeguarded is","images":[],"options":{"A":"Knowledge acquisition","B":"Judicial independence","C":"Press censorship","D":"Improved standard of living"},"answer":"B","explanation":"The best means through which individual rights can be safeguarded is through judicial independence. Judicial independence refers to the concept that the judiciary should be independent from the other branches of government. That is, courts should not be subject to improper influence from the other branches of government or from private or partisan interests. Judicial independence is vital and important to the idea of separation of powers.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>10","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"The effect of queuing up in public places is","images":[],"options":{"A":"Orderliness","B":"Transparency","C":"Honesty","D":"Humility"},"answer":"A","explanation":"The effect of queuing up in public places is orderliness. Queuing up helps to maintain order and fairness in public places. It ensures that services are provided on a first-come, first-served basis, thereby preventing chaos and disorder.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>11","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS","question":"A father that effectively discharges his duty towards his children could be described as a","images":[],"options":{"A":"Philanthropist","B":"Celebrity","C":"Responsible parent","D":"Permissive father"},"answer":"C","explanation":"A father that effectively discharges his duty towards his children is described as a responsible parent. A responsible parent is one who takes care of the needs of his children, provides for them, and ensures their well-being. A philanthropist is someone who seeks to promote the welfare of others, typically through the donation of money. A celebrity is a famous person. A permissive father is one who allows his children to do whatever they want without setting boundaries or enforcing rules.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>12","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY","question":"A programme established to foster common ties among Nigerians is","images":[],"options":{"A":"Subsidy Re-investment Programme (SURE-P)","B":"Universal Basic Education (UBE)","C":"Education Trust Fund (ETF)","D":"National Youth Service Corps (NYSC)"},"answer":"D","explanation":"The National Youth Service Corps (NYSC) is a program established to foster common ties among Nigerians. It is a one-year mandatory service for all Nigerians who have graduated from tertiary institutions at home or abroad. The program aims to promote national unity and integration by posting corps members to states other than their states of origin. The Subsidy Re-investment Programme (SURE-P), Universal Basic Education (UBE), and Education Trust Fund (ETF) are all programs aimed at improving various aspects of the Nigerian society, but they do not specifically aim to foster common ties among Nigerians.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>13","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS","question":"Use the dialogue below to answer this question   Ade: Uche, are you not going to work today?  Uche: I will go, but by public transport.  Ade: Why?  Uche: One of the side mirrors of my car is broken and also, the car emits excessive smoke.    Uche's action, based on the dialogue above, can help in","images":[],"options":{"A":"Reducing road accidents.","B":"Increasing air pollution.","C":"Encouraging public transportation.","D":"Ensuring vehicle's functionality."},"answer":"A","explanation":"From the dialogue, Uche decided not to use his car because it has a broken side mirror and it emits excessive smoke. This decision can help in reducing road accidents because a broken side mirror can limit the driver's view of the road, which can lead to accidents. Also, excessive smoke from a car can impair visibility for other road users, leading to accidents. Therefore, by not using his car, Uche is helping to reduce the possibility of road accidents.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>14","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS","question":"Use the dialogue below to answer this question   Ade: Uche, are you not going to work today?  Uche: I will go, but by public transport.  Ade: Why?  Uche: One of the side mirrors of my car is broken and also, the car emits excessive smoke.  An implication of Uche's action from the above dialogue is that he is","images":[],"options":{"A":"Afraid of Federal Road Safety Corps.","B":"Considerate of other road users.","C":"Afraid of Civil Defence Corps.","D":"Environmentally friendly"},"answer":"D","explanation":"Uche's decision to use public transport instead of his car that emits excessive smoke shows that he is environmentally friendly. Excessive smoke from vehicles contributes to air pollution, which is harmful to the environment. By choosing not to use his car until it is fixed, Uche is preventing further air pollution, thus showing consideration for the environment.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>15","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS","question":"Use the dialogue below to answer this question   Ade: Uche, are you not going to work today?  Uche: I will go, but by public transport.  Ade: Why?  Uche: One of the side mirrors of my car is broken and also, the car emits excessive smoke.  From the above dialogue, it could be implied that Uche is mindful of","images":[],"options":{"A":"Driving school code.","B":"When to use public transport.","C":"Traffic regulations.","D":"His obligation as a citizen."},"answer":"D","explanation":"From the dialogue, Uche is mindful of his obligation as a citizen. This is evident from his decision to not drive his car because it has a broken side mirror and emits excessive smoke. This shows his concern for safety and environmental pollution, which are part of a citizen's obligations.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>16","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS","question":"Which of the following is not a skill for settling intercommunal conflict?","images":[],"options":{"A":"War","B":"Dialogue","C":"Mediation","D":"Arbitration"},"answer":"A","explanation":"War is not a skill for settling intercommunal conflict. It is rather a result of failed conflict resolution. The other options - Dialogue, Mediation, and Arbitration - are all peaceful means of resolving conflicts.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>17","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS","question":"One of the advantages of inter-communal relationship is that it ensures the","images":[],"options":{"A":"Existence of totalitarianism","B":"Domination of the minority by the majority","C":"Domination of the majority by the minority","D":"Enhancement of security"},"answer":"D","explanation":"Inter-communal relationships refer to the relationships between different communities. These relationships can be beneficial in many ways, one of which is the enhancement of security. When communities have good relationships with each other, they can work together to ensure the safety and security of their members. This is because they can share information and resources, and support each other in times of need. Therefore, the correct answer is 'Enhancement of security'. The other options do not accurately represent the advantages of inter-communal relationships.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>18","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS","question":"Which of the following skills negates the promotion of interpersonal relationship?","images":[],"options":{"A":"Tolerance","B":"Selfishness","C":"Caring","D":"Kindness"},"answer":"B","explanation":"Interpersonal relationships are relationships between individuals. These relationships can be enhanced by positive traits such as tolerance, caring, and kindness. However, selfishness is a trait that can negatively affect interpersonal relationships. When a person is selfish, they prioritize their own needs and wants over those of others. This can lead to conflict and tension in relationships. Therefore, the correct answer is 'Selfishness'. The other options are traits that would promote, not negate, interpersonal relationships.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>19","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Use the cartoon below to answer questions       The cartoon is an evidence that cultism is","images":["data:image/png;base64,"],"options":{"A":"violent in nature.","B":"terrorist in nature.","C":"martial in nature.","D":"Militant in nature."},"answer":"A","explanation":"Cultism is Violent in nature. This is the most appropriate answer","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>20","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Use the cartoon below to answer questions     What does the boy need the bullet proof vest for?","images":["data:image/png;base64,"],"options":{"A":"Demonstration","B":"Protection","C":"Battle","D":"Vengeance"},"answer":"B","explanation":"Bullet proof vest is needed for protection. This is the most appropriate answer","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>21","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY","question":"Use the cartoon below to answer questions     It could be inferred from the cartoon that the activities of cult groups on campus may not be reduced by","images":["data:image/png;base64,"],"options":{"A":"Religious Instruction","B":"Campaign against cultism","C":"Relevant legislation","D":"Bullet proof vest"},"answer":"D","explanation":"Bullet proof vest can not reduced the activities of cult group on campus.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>22","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : HOW DRUGS ARE ABUSED","question":"Which of the following is not a common way by which people abuse drugs?","images":[],"options":{"A":"Ingestion","B":"Intrusion","C":"Inhalation","D":"Injection"},"answer":"B","explanation":"Drug abuse refers to the misuse of substances, especially drugs or alcohol, for purposes such as achieving calming or euphoric effects, to the detriment of one's health. The common ways by which people abuse drugs include ingestion (taking by mouth), inhalation (breathing in), and injection (directly into the bloodstream). Intrusion is not a recognized method of drug abuse.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>23","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES","question":"The establishment of the National Drug Law Enforcement Agency (NDLEA)","images":[],"options":{"A":"Make drugs available to the masses","B":"prevent drug abuse","C":"encourage the use of drug by the masses","D":"Support importation of drugs"},"answer":"B","explanation":"The National Drug Law Enforcement Agency (NDLEA) is a Federal agency in Nigeria charged with eliminating the growing, processing, manufacturing, selling, exporting, and trafficking of hard drugs. The agency was established by Decree Number 48 of 1989. The NDLEA is present in international airports, seaports and border crossing. It tries to eradicate cannabis by destroying plantings. The NDLEA also targets the leaders of narcotics and money laundering organizations. Its aim is to prevent drug abuse, not to make drugs available to the masses, encourage the use of drugs by the masses, or support the importation of drugs.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>24","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE","question":"A common repercussion for drug abuse is","images":[],"options":{"A":"Medication","B":"Rehabilitation","C":"Brain drain","D":"Memory loss"},"answer":"D","explanation":"Drug abuse often leads to various health issues, including memory loss. This is because drugs can alter important brain areas that are necessary for life-sustaining functions and can drive the compulsive drug abuse that marks addiction. Brain changes that occur over time with drug use challenge an addicted person's self-control and interfere with their ability to resist intense impulses to take drugs. Hence, memory loss is a common repercussion for drug abuse.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>25","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE","question":"Which of the following is a way of preventing drug trafficking?","images":[],"options":{"A":"Foreign scholarship","B":"Employment","C":"Motivation","D":"Indulging offenders"},"answer":"B","explanation":"Employment can be a way of preventing drug trafficking. When people are gainfully employed, they are less likely to engage in illegal activities such as drug trafficking. Employment provides a means of livelihood and reduces the economic incentive to engage in drug trafficking. None of the other options provided (Foreign scholarship, Motivation, Indulging offenders) directly prevent drug trafficking.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>26","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"A major consequence of human trafficking is","images":[],"options":{"A":"Promotion of rural-urban drift.","B":"Decline in literacy rate.","C":"Increased rate of youth employment.","D":"Increased exploitation of the ignorant."},"answer":"D","explanation":"Human trafficking often leads to the exploitation of the ignorant. Victims are often deceived or coerced into situations where they are exploited for labor, sexual purposes, or other forms of servitude. This exploitation is a major consequence of human trafficking. The other options do not directly relate to the consequences of human trafficking.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>27","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"Human trafficking results into all the following except","images":[],"options":{"A":"Prostitution","B":"Migration","C":"Criminality","D":"Welfarism"},"answer":"D","explanation":"Welfarism is not a result of human trafficking. Welfarism refers to the system in which the welfare of the citizens is the responsibility of the state. Human trafficking, on the other hand, is a criminal activity that involves the illegal trade of people for exploitation or commercial gain. The other options, prostitution, migration, and criminality, can be results of human trafficking.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>28","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"The group of individuals in the society that is mostly prone to human trafficking are","images":[],"options":{"A":"Women and children","B":"Youths, women and men","C":"Men and vulnerable children","D":"Old and weak individuals"},"answer":"A","explanation":"Human trafficking is a serious crime and a grave violation of human rights. Every year, thousands of men, women and children fall into the hands of traffickers, in their own countries and abroad. However, women and children are the most vulnerable and are often the primary targets of human trafficking due to their perceived lack of power and their marginalized status in many societies. This makes them more susceptible to manipulation and coercion.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>29","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS","question":"An enlightenment and awareness campaign on HIV/AIDS could","images":[],"options":{"A":"lead to discrimination","B":"Create job opportunities","C":"cause conflict","D":"Provide people with genuine information"},"answer":"D","explanation":"An enlightenment and awareness campaign on HIV/AIDS is designed to provide people with genuine information about the disease, its causes, prevention methods, and treatment options. This helps to dispel myths and misconceptions about the disease, reduce stigma and discrimination, and promote safe practices. It does not lead to discrimination or cause conflict, and while it may create job opportunities in the health and social work sectors, this is not its primary purpose.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>30","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS","question":"Which of these is not a form of stigmatization?","images":[],"options":{"A":"Refusal to interact with family of an HIV patient","B":"Physical and verbal abuse of HIV/AIDS patient","C":"Ostracising HIV patient","D":"Enlighening people living with HIV/AIDS"},"answer":"D","explanation":"Stigmatization refers to the act of discriminating or treating someone unfairly due to their condition or status. Enlightening people living with HIV/AIDS is not a form of stigmatization, but rather a positive action aimed at providing them with necessary information and support.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>31","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS","question":"Testing of blood before transfusion will greatly help to","images":[],"options":{"A":"Spread HIV","B":"Control HIV","C":"Eradicate HIV","D":"Prevent HIV"},"answer":"D","explanation":"Testing of blood before transfusion is a preventive measure to ensure that the blood to be transfused is not infected with HIV. This helps to prevent the spread of HIV.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>32","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS","question":"From the above report, which of the following is the major consequence of the intervention programme?","images":[],"options":{"A":"Increase in self-reliance skills","B":"Promotion of intercommunal relation","C":"Provision of infrastructural facilities","D":"Acceleration of national development"},"answer":"D","explanation":"The question refers to a report that is not provided, making it impossible to determine the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>33","subject":"Civic Education","year":"2018","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING","question":"From the above report, a probable reason for the initial high crime rate in in Aikara community was","images":[],"options":{"A":"Poor upbringing","B":"Corruption","C":"Abject poverty","D":"Greed"},"answer":"C","explanation":"The question refers to a report that is not provided, making it impossible to determine the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>34","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"One of the functions of local government is","images":[],"options":{"A":"Settlement of intra-party crisis","B":"Making of bye-laws","C":"Formulation of monetary policies","D":"Delimitation of constituencies"},"answer":"B","explanation":"The function of local government includes making of bye-laws. Bye-laws are laws that are made by a local authority and apply only within its particular area. They are used to deal with issues that are of local concern, such as regulating businesses, controlling land use, or managing public health and safety.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>35","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"A body established and entrusted with power and authority to direct the affairs of a state is called","images":[],"options":{"A":"Federal Executive Council","B":"State Legislative Council","C":"Trusteeship","D":"Government"},"answer":"D","explanation":"A body established and entrusted with power and authority to direct the affairs of a state is called a Government. The government is the governing body of a nation, state, or community. It is responsible for the creation of laws, the enforcement of laws, and the protection of the state and its citizens.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>36","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW","question":"Which of the following concepts can guarantee adherence to the rule of law?","images":[],"options":{"A":"Political immunity","B":"Political gerrymandering","C":"National development","D":"Representative democracy"},"answer":"D","explanation":"The concept that can guarantee adherence to the rule of law is 'Representative democracy'. In a representative democracy, citizens elect representatives to make laws and decisions on their behalf, ensuring that the rule of law is upheld. Political immunity and political gerrymandering do not guarantee adherence to the rule of law. National development is a broad concept that includes adherence to the rule of law, but it is not a concept that can guarantee it.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>37","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT","question":"According to the 1999 constitution sovereignty resides in the","images":[],"options":{"A":"Commander-in-Chief of the Armed Forces.","B":"People who confer legitimacy on elected leaders.","C":"National Assembly which has power to make laws and amend the constitution.","D":"Military which can declare any law null, void and of no effect."},"answer":"B","explanation":"According to the 1999 constitution, sovereignty resides in the 'People who confer legitimacy on elected leaders'. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In a democratic society, the people are the source of sovereignty. They confer legitimacy on elected leaders through the process of voting. The other options do not correctly represent where sovereignty resides according to the constitution.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>38","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"In a democratic government, franchise is given to all","images":[],"options":{"A":"Party members.","B":"Resident adults.","C":"Adult citizens.","D":"Opinion leaders."},"answer":"C","explanation":"In a democratic government, franchise, which is the right to vote, is given to all adult citizens. This is because democracy is a system of government where citizens exercise power by voting. Therefore, all adult citizens are given the right to vote irrespective of their party affiliation, residency status, or influence.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>39","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW","question":"A Significant companion of the rule of law is the","images":[],"options":{"A":"Fusion of legislative and executive functions","B":"Supremacy of the ordinary law","C":"Adoption of one party system","D":"Enforcement of law by the legislature"},"answer":"B","explanation":"A significant companion of the rule of law is the supremacy of the ordinary law. The rule of law is a principle that all people and institutions are subject to and accountable to law that is fairly applied and enforced. Therefore, the supremacy of the ordinary law means that no individual or government is above the law, and all are subject to the same laws.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>40","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW","question":"Operation of the rule of law could be undermined by the","images":[],"options":{"A":"Existence of civil society groups.","B":"Existence of free press.","C":"Establishment of administrative tribunals.","D":"Encouragement of effective opposition."},"answer":"C","explanation":"The rule of law is a principle that ensures that all individuals and institutions are subject to and accountable to laws that are fairly applied and enforced. The establishment of administrative tribunals can undermine the operation of the rule of law because they can make decisions without the same level of scrutiny and accountability as a court of law. This can lead to arbitrary or unfair decisions. The other options, such as the existence of civil society groups and free press, and the encouragement of effective opposition, are generally seen as supporting the rule of law, not undermining it.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>41","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Use the dialogue below to answer this question   Ini: The recent Constitution Conference organized by federal government gulped a lot of money.  Emem: That type of conference can only happen where there is a democratic governance which permits respect for all shades of opinion.  Ini: So, the federal government cannot solely take decisions and ratify them?  Emem: No, that will negate the fundamental principles of democracy.    The above dialogue shows that democracy could result into","images":[],"options":{"A":"Inefficiency","B":"Corruption","C":"Absolute liberty","D":"High cost of governance"},"answer":"D","explanation":"The dialogue between Ini and Emem discusses the cost of a Constitution Conference organized by the federal government. Emem explains that such a conference, which allows for a variety of opinions to be heard, is a characteristic of democratic governance. However, this can lead to a high cost of governance, as it requires resources to facilitate such processes. Therefore, the dialogue suggests that democracy could result in a high cost of governance. The other options, such as inefficiency, corruption, and absolute liberty, are not directly suggested by the dialogue.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>42","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Use the dialogue below to answer this question   Ini: The recent Constitution Conference organized by federal government gulped a lot of money.  Emem: That type of conference can only happen where there is a democratic governance which permits respect for all shades of opinion.  Ini: So, the federal government cannot solely take decisions and ratify them?  Emem: No, that will negate the fundamental principles of democracy.  It could be inferred from the dialogue above that democracy encourages","images":[],"options":{"A":"Tolerance","B":"Development","C":"Job creation","D":"Delegated legislation"},"answer":"A","explanation":"From the dialogue, it can be inferred that democracy encourages 'Tolerance'. This is because Emem mentions that a democratic governance permits respect for all shades of opinion, which is a form of tolerance. Tolerance in this context refers to the acceptance of differing views and opinions, which is a fundamental principle of democracy.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>43","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"The most suitable form of democracy for a small village or community is","images":[],"options":{"A":"Constitution democracy","B":"Indirect democracy","C":"Communal democracy","D":"Direct democracy"},"answer":"D","explanation":"The most suitable form of democracy for a small village or community is 'Direct democracy'. In a direct democracy, all members of the community have the right to participate in decision-making processes. This is more feasible in smaller communities where it is easier to gather all members for discussions and decisions. In contrast, indirect or representative democracy is more suitable for larger societies where it is impractical for everyone to participate directly in decision-making.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>44","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY","question":"Which of the following is not a major reason for political apathy?","images":[],"options":{"A":"Political violence","B":"Unfulfilled political promises","C":"Bad governance","D":"Cross carpeting phenomenon"},"answer":"D","explanation":"Political apathy refers to the indifference in attitude of the citizens towards political activities. It's often caused by factors such as political violence, unfulfilled political promises, and bad governance. However, cross carpeting phenomenon, which refers to the act of switching from one political party to another, is not a major reason for political apathy. It's more of a political strategy used by politicians rather than a cause for citizens' indifference towards politics.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>45","subject":"Civic Education","year":"2018","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"The Chapter IV of the 1999 constitution of Nigeria is about","images":[],"options":{"A":"Composition of the National Assembly","B":"Fundamental human rights","C":"Procedures for the impeachment of the president","D":"Formation of quorum in the Senate"},"answer":"B","explanation":"The Chapter IV of the 1999 constitution of Nigeria is about Fundamental Human Rights. These rights are guaranteed to all citizens and they include rights such as the right to life, right to dignity of human person, right to personal liberty, right to fair hearing, right to private and family life, right to freedom of thought, conscience and religion, right to freedom of expression and the press, etc.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>46","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY","question":"Which of the following may prevent a citizen from voting in a general election?","images":[],"options":{"A":"Lack of stable income","B":"High cost of living","C":"Non-registration","D":"Political neutrality"},"answer":"C","explanation":"A citizen may be prevented from voting in a general election if they have not registered to vote. Registration is a prerequisite for voting in many countries. It is the process where eligible citizens of a country indicate their intention to vote in an election by having their names, and often other identifying information, entered in a register (also known as electoral roll). This ensures that only eligible citizens vote in an election. Therefore, non-registration can prevent a citizen from voting.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>47","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY","question":"An organised group that is independent of the state could be described as","images":[],"options":{"A":"Civil defence","B":"Pressure group","C":"Community group","D":"Civil society"},"answer":"D","explanation":"A civil society is an organized group that is independent of the state. It refers to the space for collective action around shared interests, purposes and values, generally distinct from government and commercial for-profit actors. Civil society includes charities, development NGOs, community groups, women's organizations, faith-based organizations, professional associations, trade unions, social movements, coalitions and advocacy groups.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>48","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE","question":"The smooth operation of the Public Service in Nigeria is being hampered by","images":[],"options":{"A":"Debt burden","B":"Adequate training","C":"Privatization policy","D":"Bribery and corruption"},"answer":"D","explanation":"The smooth operation of the Public Service in Nigeria is being hampered by bribery and corruption. This is because corruption leads to inefficiency, misappropriation of public funds, and a lack of accountability, which hampers the smooth operation of the public service.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2018>49","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"The Public Service can perform all these functions except","images":[],"options":{"A":"Advise government on policy formulation","B":"keeping of government records","C":"Provision of social services","D":"budget approval for implementation"},"answer":"D","explanation":"The Public Service can perform all these functions except budget approval for implementation. The approval of the budget for implementation is the responsibility of the legislative arm of government, not the public service. The public service can advise on policy formulation, keep government records, and provide social services, but it does not have the power to approve budgets.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2018>50","subject":"Civic Education","year":"2018","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : MEANING OF PUBLIC SERVICE","question":"The highest class in the Public Service in Nigeria is the","images":[],"options":{"A":"Clerical","B":"Manipulative","C":"Technical","D":"Administrative"},"answer":"D","explanation":"The highest class in the Public Service in Nigeria is the Administrative class. The Public Service is a hierarchical system and the Administrative class is at the top of this hierarchy. They are responsible for making key decisions and implementing policies.","marks":"1","difficulty":"1"}];